import './Icon.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import type { ColorTypes } from '../../types/status';
import { useColorInteadOfStatus } from '../../types/status';
import type { IconProps } from './Icon.types';

export const Icon = forwardRef<HTMLSpanElement, IconProps>(
	({ iconName, size = 'medium', type, className, contained, color, dataTestId = 'Icon', ...props }, ref) => {
		// TODO: удалить при удалении пропса type (не забудь указать пропсу color дефолтное значение)
		// при удалении заменить использование iconColor на color
		const iconColor: ColorTypes = useColorInteadOfStatus({ color, type }, 'Icon');

		// TODO: удалить при удалении пропса type
		// при удалении заменить использование isContained на contained
		const isContained = contained || Boolean(type);

		return (
			<span
				{...props}
				data-testid={dataTestId}
				role="img"
				className={classNames(
					'beeline-icons',
					'dsb_icon',
					isContained && 'dsb_icon--contained',
					isContained && `dsb_icon--${iconColor}`,
					!isContained && `dsb_icon--${size}`,
					!isContained && `dsb_icon--sized--${iconColor}`,
					className,
				)}
				translate="no"
				ref={ref}
			>
				{iconName}
			</span>
		);
	},
);
